  ('aboriginal-d0d1b9a2-moex-00018', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，下列關於甲機關 X3 年度預算執行材料交易，會', '["將X1年度購置材料價款以X3年度預算數辦理繳庫", "X3年度購 買材料", "X3年度計畫使用材料", "X2年度已奉准保留之計畫使用材料"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "f28ec9747297", "answer_pdf_sha1": "297856bc2cb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00019', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定，下列交易事項何者一定不會影響當年度之支出數', '["固定資產辦理重估增值時", "取得遞耗資產時", "已達耐用年限固定資產報廢時", "辦 理可提升固定資產服務能量之大修時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "f28ec9747297", "answer_pdf_sha1": "297856bc2cb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00020', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '甲稅捐機關將依法收到納稅義務人抵繳稅款之實物變現並繳庫，依中央政府普通公務單位會計制 度之一致規定，下列敘述何者正確？', '["按帳面值變現時，借記公庫撥入數科目", "變現數超過帳面值時，超過金額應貸記資產負債淨額科目", "變現數少於帳面值時，若本年度已認列收入科目，少於金額應借記遞延收入科目", "變現數少於帳面值時，若以前年度已認列收入科目，少於金額應借記資產負債淨額科目"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "f28ec9747297", "answer_pdf_sha1": "297856bc2cb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00021', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依現行實務之作法，下列敘述何者正確？①會計報告中應揭露預算及其實際執行結果之比較資', '["會計報告中應揭露預算及其實際執行結果之 比較資訊，以提供報告使用者評估政府之施政績效責任", "各機關依預算控制類科目登帳後，係 於會計報告相關報表中以可支用預算數、累計分配數、累計實現數及執行較分配增減數等欄位呈 現", "各機關依預算控制類科目登帳後，直接於平衡表或收入支出表中顯示所有預算控制類科目 之餘額", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "f28ec9747297", "answer_pdf_sha1": "297856bc2cb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00022', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定及政府會計準則公報第2號規定，丁地方政府於X4 年3月收到年度預算外，中央政府未指定用途的補助款1,000萬元，其應作之分錄為何？', '["借：繳付公庫數1,000萬元，貸：暫收款1,000萬元", "借：繳付公庫數1,000萬元，貸：補助收入1,000萬元", "借：繳付公庫數1,000萬元，貸：預收其他政府款1,000萬元", "借：繳付公庫數1,000萬元，貸：應付代收款1,000萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "f28ec9747297", "answer_pdf_sha1": "297856bc2cb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00023', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'essay', '甲公司採直線法提列折舊，該公司於 X1 年中更換廠房設備，X1年 1 月
