  ('aboriginal-d0d1b9a2-moex-00025', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X4年1月1日買入一設備，成本$400,000，估計耐用年限6年，殘值$16,000，以直線 法提列折舊。X5年1月1日進行定期維修費用$5,000，並添購新配件$60,000，本次添購配件預計 可增加設備每年50%的生產力。若原設備耐用年限不變，但殘值提升至$21,000，則甲公司X5年 應認列之折舊費用為何？', '["$62,500", "$63,000", "$75,000", "$76,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00026', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲牧場飼養的羊隻於X5年9月30日共生產羊乳10,000公升，每公升羊乳市價為$210，運送至 市場之運輸成本每公升$10，出售成本每公升為$5。當月份發生飼料費用$50,000，採收羊乳工資 $26,000，其他支出$35,000，試問甲牧場採集的羊乳入帳金額是多少？', '["$1,839,000", "$1,950,000", "$2,026,000", "$2,061,000 60740"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00027', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-114-d35177eb', 'sub-aboriginal-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X5年7月1日出售一台特殊機器給乙客戶，並提供一年內免費更換零件的售後服務保 證，估計每個零件更換成本為$50,000。若甲公司評估發生一個零件故障機率為30%，二個零件故 障機率為60%，三個零件故障機率為10%，則甲公司X5年應認列估計產品保證負債金額為何？', '["$0", "$60,000", "$90,000", "$100,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:03+00:00", "source_pdf_sha1": "253eaf65d94c", "answer_pdf_sha1": "9b18364fc8b2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "607", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL)
